-- ========================================
-- FR-3.1 인허가 체크리스트 관련 테이블 DDL + 데이터
-- 작성자: 최지원
-- ========================================

-- ========================================
-- 1. DDL - 테이블 생성
-- ========================================

-- license_industries (인허가 업종 정보)
CREATE TABLE IF NOT EXISTS license_industries (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name VARCHAR(100) NOT NULL,
    law_name VARCHAR(200) NOT NULL,
    law_article VARCHAR(100),
    license_type VARCHAR(20) NOT NULL,
    department VARCHAR(100) NOT NULL
);

-- surveys (조건 질문)
CREATE TABLE IF NOT EXISTS surveys (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    license_id UUID NOT NULL REFERENCES license_industries(id) ON DELETE CASCADE,
    question VARCHAR(300) NOT NULL,
    order_num SMALLINT NOT NULL
);

-- documents (필요 서류)
CREATE TABLE IF NOT EXISTS documents (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    license_id UUID NOT NULL REFERENCES license_industries(id) ON DELETE CASCADE,
    name VARCHAR(200) NOT NULL,
    issuer VARCHAR(100) NOT NULL,
    is_common BOOLEAN NOT NULL DEFAULT false
);

-- survey_documents (조건부 서류 연결)
CREATE TABLE IF NOT EXISTS survey_documents (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    survey_id UUID NOT NULL REFERENCES surveys(id) ON DELETE CASCADE,
    answer BOOLEAN NOT NULL,
    document_id UUID NOT NULL REFERENCES documents(id)
);

-- checklist_steps (방문 동선)
CREATE TABLE IF NOT EXISTS checklist_steps (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    license_id UUID NOT NULL REFERENCES license_industries(id) ON DELETE CASCADE,
    order_num SMALLINT NOT NULL,
    place VARCHAR(100) NOT NULL,
    task VARCHAR(300) NOT NULL,
    estimated_days VARCHAR(50)
);

-- license_industry_mappings (업종-인허가 매핑)
CREATE TABLE IF NOT EXISTS license_industry_mappings (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    category_id UUID NOT NULL REFERENCES industry_categories(id),
    license_id UUID NOT NULL REFERENCES license_industries(id)
);

-- checklist_progresses (스테퍼 진행 상황)
CREATE TABLE IF NOT EXISTS checklist_progresses (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    license_id UUID NOT NULL REFERENCES license_industries(id),
    current_step SMALLINT NOT NULL DEFAULT 1,
    industry_code VARCHAR(50),
    conditions JSONB,
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

