INSERT INTO surveys (id, license_id, question, order_num) VALUES
('b1000000-0000-0000-0000-000000000001', 'a1000000-0000-0000-0000-000000000001', '지하수를 조리·세척 등에 사용할 예정인가요?', 1),
('b1000000-0000-0000-0000-000000000002', 'a1000000-0000-0000-0000-000000000001', '영업장이 지하 66㎡ 이상 또는 2층 이상 100㎡ 이상인가요?', 2),
('b1000000-0000-0000-0000-000000000003', 'a1000000-0000-0000-0000-000000000001', 'LPG(액화석유가스)를 사용할 예정인가요?', 3),
('b1000000-0000-0000-0000-000000000004', 'a1000000-0000-0000-0000-000000000001', '어린이놀이시설을 설치할 예정인가요?', 4),
('b1000000-0000-0000-0000-000000000005', 'a1000000-0000-0000-0000-000000000002', '지하수를 조리·세척 등에 사용할 예정인가요?', 1),
('b1000000-0000-0000-0000-000000000006', 'a1000000-0000-0000-0000-000000000002', '영업장이 지하 66㎡ 이상 또는 2층 이상 100㎡ 이상인가요?', 2),
('b1000000-0000-0000-0000-000000000007', 'a1000000-0000-0000-0000-000000000002', 'LPG(액화석유가스)를 사용할 예정인가요?', 3),
('b1000000-0000-0000-0000-000000000008', 'a1000000-0000-0000-0000-000000000002', '어린이놀이시설을 설치할 예정인가요?', 4),
('b2000000-0000-0000-0000-000000000001', 'a2000000-0000-0000-0000-000000000001', '영업장 면적이 150㎡ 이상인가요? (다중이용업소 해당 여부)', 1),
('b2000000-0000-0000-0000-000000000002', 'a2000000-0000-0000-0000-000000000001', '건물 소유자와 임대차계약서 임대인이 다른가요?', 2),
('b3000000-0000-0000-0000-000000000001', 'a3000000-0000-0000-0000-000000000001', '피부미용, 네일, 메이크업 등 종합미용업으로 운영할 예정인가요?', 1),
('b3000000-0000-0000-0000-000000000002', 'a3000000-0000-0000-0000-000000000001', '국유철도 정거장 또는 군사시설 내에서 영업할 예정인가요?', 2),
('b4000000-0000-0000-0000-000000000001', 'a4000000-0000-0000-0000-000000000001', '건물 일부를 대상으로 숙박업 영업신고를 하나요?', 1),
('b4000000-0000-0000-0000-000000000002', 'a4000000-0000-0000-0000-000000000001', '지하수를 식수 또는 조리에 사용할 예정인가요?', 2),
('b4000000-0000-0000-0000-000000000003', 'a4000000-0000-0000-0000-000000000002', '주택 소유자가 아닌 임차인으로 신고하나요?', 1),
('b4000000-0000-0000-0000-000000000004', 'a4000000-0000-0000-0000-000000000002', '조식 제공을 위해 지하수를 사용할 예정인가요?', 2),
('b5000000-0000-0000-0000-000000000001', 'a5000000-0000-0000-0000-000000000001', '타인 소유의 부동산을 임차하여 운영할 예정인가요?', 1),
('b5000000-0000-0000-0000-000000000002', 'a5000000-0000-0000-0000-000000000001', '체육지도자(생활스포츠지도사 등)를 배치할 예정인가요?', 2),
('b6000000-0000-0000-0000-000000000001', 'a6000000-0000-0000-0000-000000000001', '법인으로 설립할 예정인가요?', 1),
('b6000000-0000-0000-0000-000000000002', 'a6000000-0000-0000-0000-000000000001', '교습장소를 임차하여 운영할 예정인가요?', 2),
('b7000000-0000-0000-0000-000000000001', 'a7000000-0000-0000-0000-000000000001', '한약사로 개설하는 경우인가요?', 1),
('b7000000-0000-0000-0000-000000000002', 'a7000000-0000-0000-0000-000000000001', '한약을 조제·판매할 예정인가요?', 2),
('b8000000-0000-0000-0000-000000000001', 'a8000000-0000-0000-0000-000000000001', '법인으로 개설할 예정인가요?', 1),
('b8000000-0000-0000-0000-000000000002', 'a8000000-0000-0000-0000-000000000001', '사무소를 임차하여 운영할 예정인가요?', 2);
